from flask import Flask, send_file, abort, g
import os
from pathlib import Path

app = Flask(__name__)

INVOICE_DIR = Path(os.environ.get("INVOICE_DIR", "./invoices")).resolve()


def get_invoice_path(invoice_id: int) -> Path:
    return INVOICE_DIR / f"{invoice_id}.pdf"


@app.get("/api/invoices/<int:invoice_id>/download")
def download_invoice(invoice_id: int):
    if invoice_id <= 0:
        abort(404)

    invoice_path = get_invoice_path(invoice_id)
    if not invoice_path.is_file():
        abort(404)

    return send_file(
        invoice_path,
        mimetype="application/pdf",
        as_attachment=True,
        download_name=f"invoice-{invoice_id}.pdf",
        conditional=True,
    )


